local ModelCrossGrading = LxClass("ModelCrossGrading",LModel)

ModelCrossGrading.ATTACK_TYPE = 1 				-- 攻击方
ModelCrossGrading.DEFEND_TYPE = 2				-- 防守方

ModelCrossGrading.GAME_OVER = 0         		-- 未开启
ModelCrossGrading.GAME_START = 1        		-- 开启
ModelCrossGrading.GAME_END = 2        			-- 结束

ModelCrossGrading.SCOREUP_MAX = -1      		-- 表示段位积分上限，-1代表无穷大

ModelCrossGrading.CHALLENGE_REWARD = 1			-- 挑战奖励
ModelCrossGrading.GRADING_REWARD = 2			-- 段位奖励
