function ModelCrossGrading:ModelCrossGrading()
	self._sortStatusNum = {
		[0] = 2,
		[1] = 3,
		[2] = 1,
	}
	self._timer = nil

	self._battleStatus = false
end

--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelCrossGrading:OnModelInit()
	self:ModelNetMsgRecv(LProtoIds.CrossRankMatchInfoResp,function(...) self:OnCrossRankMatchInfoResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.CrossRankBattleResp,function(...) self:OnCrossRankBattleResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.CrossRankReceiveResp,function(...) self:OnCrossRankReceiveResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.CrossRankReportListResp,function(...) self:OnCrossRankReportListResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.CrossRankGroupInfoResp,function(...) self:OnCrossRankGroupInfoResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.CrossRankBalanceInfoResp,function(...) self:OnCrossRankBalanceInfoResp(...) end)
	self:ModelNetMsgRecv(LProtoIds.CrossRankReceiveAllResp,function(...) self:OnCrossRankReceiveAllResp(...) end)

	local pbId = LProtoHelper.GetProtoId("CrossRankBattleResp")
	self:ModelEventRecv(EventNames.NET_ERROR_CODE, function(msgId)
		if pbId == msgId then
			GF.CloseWndByName("UICrossGradingMatchTime")
		end
	end)
	self:InitCrossGradingConfigRef()
	self:InitCrossGradingIntervalRef()
	self:InitCrossGradingCombatAwardRef()
end

function ModelCrossGrading:OnCrossRankPkListReq()
	local pb = LProtoHelper.CreateProto(LProtoIds.CrossRankPkListReq)
	SendMessage(pb,LProtoIds.CrossRankPkListReq)
end

function ModelCrossGrading:OnCrossRankPkReq(playerId)
	local pb = LProtoHelper.CreateProto(LProtoIds.CrossRankPkReq)
	pb.playerId = playerId
	SendMessage(pb,LProtoIds.CrossRankPkReq)
end


function ModelCrossGrading:OnModelRequest()
	self:OnCrossRankMatchInfoReq()
	self:ClearTimer()
	self:ModelFinish()
end

function ModelCrossGrading:ClearTimer()
	self._battleStatus = false
	self._intervalTime = nil
	local timer = self._timer
	if timer then
		LxTimer.LoopTimeStop(timer)
		self._timer = nil
	end
end

function ModelCrossGrading:StartTimer()
	self:ClearTimer()
	local matchInterval = self._matchInterval
	self._intervalTime = matchInterval
	self._timer = LxTimer.LoopTimeCall(function()
		if self._intervalTime <= 0 then
			self:ClearTimer()
		else
			self._intervalTime = self._intervalTime - 1
		end
	end,1,false,-1)
end

function ModelCrossGrading:GetMatchIntervalTime()
	return self._intervalTime
end
