function ModelCrossGrading:OnCrossRankMatchInfoResp(pb,ret)
	self.state = pb.state 							-- 状态 0:未开启 1：已开启
    self.seasonId = pb.seasonId 					-- 赛季Id
    self.endTime = pb.endTime						-- 结束时间
    self.rank = pb.rank							    -- 段位 （如排名前十）

	if not self.oldRank then
		self.oldRank = self.rank
	end

    self.score = pb.score							-- 积分

	if not self.oldScore then
		self.oldScore = self.score
	end

    self.rankMax = pb.rankMax						-- 历史最高段位
    self.rankMaster = pb.rankMaster				    -- 极宙段位 小于等于0表示无排名
    self.battleCount = pb.battleCount				-- 总挑战次数

	-- 已领取挑战宝箱奖励记录（每日刷新）
	self.battleBoxReceive = {}
	local battleBoxReceive = pb.battleBoxReceive
	for i,v in ipairs(battleBoxReceive) do
		self.battleBoxReceive[v] = v
	end

	self.rankBoxReceive = {}
	-- 已领取段位宝箱奖励记录（每赛季刷新）
	local rankBoxReceive = pb.rankBoxReceive
	for i,v in ipairs(rankBoxReceive) do
		self.rankBoxReceive[v] = v
	end

	self.teamCount = pb.teamCount



	self:RepFormationGrid()
end

