function ModelCrossGrading:OnCrossRankGroupInfoResp(pb,ret)
	local groupId = pb.groupId
	self._crossGroupId = groupId
	if not (self._openGroupForeignPop or self._openGroupPop) then
		return
	end

	local serverNames = pb.serverNames
	local serverIds = pb.serverIds
	local list = {}
	local curServerIdList = {}
	for i,v in ipairs(serverNames) do
		local curServerId = serverIds[i]
		table.insert(list,{
			serverName = v,
			serverId = curServerId
		})

		if self._openGroupForeignPop then
			curServerIdList[curServerId] = true
		end
	end

	if self._openGroupPop then
		if #list <= 0 then
			GF.ShowMessage(ccClientText(17983))
			return
		end
		GF.OpenWnd("UIKfSyerGroupingPop",{
			wndType = 2,groupId = groupId,serverList = list
		})
		self._openGroupPop = false
	elseif self._openGroupForeignPop then
		if #list <= 0 then return end
		local localServerList = string.split(LPlayerPrefs.foreignGradingServerList, "|")

		local combatTypeConst = LCombatTypeConst.COMBAT_CROSSGRADING_RANK
		local combatType, gradingServerListStr, saveListStr
		for k,v in ipairs(localServerList) do
			local curLocalData = string.split(v, "=")
			combatType = tonumber(curLocalData[1])
			if combatType == combatTypeConst then
				gradingServerListStr = curLocalData[2]
			else
				if not saveListStr then
					saveListStr = v
				else
					saveListStr = saveListStr.."|"..v
				end
			end
		end

		local isSame = true
		if not string.isempty(gradingServerListStr) then
			local gradingServerList = string.split(gradingServerListStr, "-")
			for k,v in ipairs(gradingServerList) do
				if not curServerIdList[tonumber(v)] then
					isSame = false
					break
				else
					curServerIdList[tonumber(v)] = false
				end
			end

			if isSame then
				for k,v in pairs(curServerIdList) do
					if v == true then
						isSame = false
					end
				end
			end
		else
			isSame = false
		end
		if isSame then return end

		if not saveListStr then
			saveListStr = combatTypeConst.."="
		else
			saveListStr = saveListStr.."|"..combatTypeConst.."="
		end

		local saveNum = 0
		for k,v in pairs(curServerIdList) do
			if saveNum == 0 then
				saveListStr = saveListStr..k
			else
				saveListStr = saveListStr.."-"..k
			end
			saveNum = saveNum + 1
		end

		LPlayerPrefs.SetForeignGradingServerList(saveListStr)

		--if gLGameLanguage:IsUSARegion() then
			GF.OpenWnd("WndCrossServerGroupingForeignPop",{
				groupId = groupId,serverList = list
			})
		--end

		self._openGroupForeignPop = false
	end
end

function ModelCrossGrading:OnCrossRankBalanceInfoResp(pb,ret)
	local rankMax = pb.rankMax
	if rankMax == 0 then
        self:TryOpenGroupWndForeignPop()
        return
    end
	local combatTotal = pb.combatTotal
	local initScore = pb.initScore
	local seasonId = pb.seasonId
	local info = {
		combatTotal = combatTotal,
		rankMax = rankMax,
		initScore = initScore,
		seasonId = seasonId,
	}
	local func = function()
        self:TryOpenGroupWndForeignPop()
	end

	if pb.offlineInfo and not string.isempty(pb.offlineInfo) then
		local info = JSON.decode(pb.offlineInfo)
		local sorce = tonumber(info.a5)
		local id = sorce > 0 and 150020 or 150021
		gModelGeneral:OpenUIOrdinTips({
			refId = id,
			para = { info.a1, info.a2, info.a3, info.a4, math.abs(sorce) }
		})
	end

	--GF.OpenWnd("UIKuafuGradSeasonIdSow",{info = info, func = func})
end
