function ModelCrossGrading:IsNeedShowCrossGradingSeasonId()
	if not self.state then return false end

	if self.state ~= ModelCrossGrading.GAME_START then return false end

	local seasonId = self:GetSeasonId()
	if not seasonId then return false end
	if seasonId - 1 <= 0 then return false end

	local endTime = self:GetEndTime()
	if not endTime then return false end

	local saveEndTime = tonumber(LPlayerPrefs.crossGradingEndTime) or 0
	if saveEndTime < endTime then
		return true
	else
		return false
	end
end

function ModelCrossGrading:IsCrossGradingOpen()
	return self:GetState() == ModelCrossGrading.GAME_START
end

function ModelCrossGrading:IsCrossGradingEnd()
	return self:GetState() == ModelCrossGrading.GAME_END
end

function ModelCrossGrading:GetCrossRankReportServerData(pb)
    local report = StructCrossRankReport:New()
    report:CreateByPb(pb)
    return report
end

function ModelCrossGrading:GetRankRefIdByScore(score,rank)
	score = score or self:GetScore()
	rank = rank or self:GetRank()
	local rankRefId,curRankRefId
	local list = self:GetSortCrossGradingIntervalList()
	if list then
		for k,v in ipairs(list) do
			local tRankRefId = v.refId
			local scoreDown = v.scoreDown
			local scoreUp = v.scoreUp
			if scoreUp == -1 and score >= scoreDown then
				local playerMax = v.playerMax
				if rank > 0 and rank <= playerMax then
					rankRefId = tRankRefId
				else
					rankRefId = curRankRefId
				end
				break
			elseif score >= scoreDown and score <= scoreUp then
				rankRefId = tRankRefId
				break
			end
			curRankRefId = tRankRefId
		end
	end
	return rankRefId
end

function ModelCrossGrading:GetRankNameByScoreAndRank(score,rank,isColor)
	local ref = self:GetCurCrossGradingIntervalRef(score,rank)
	if ref then
		local name = ccLngText(ref.name)
		if isColor then
			local nameColor = ref.nameColor
			if not string.isempty(nameColor) then
				nameColor =  "#" .. nameColor
				name = LUtil.FormatColorStr(name,nameColor)
			end
		end
		return name
	end
end

function ModelCrossGrading:GetRankNameByRefId(refId,isColor)
	local ref = self:GetCrossGradingIntervalByRefId(refId)
	if ref then
		local name = ccLngText(ref.name)
		if isColor then
			local nameColor = ref.nameColor
			if not string.isempty(nameColor) then
				nameColor =  "#" .. nameColor
				name = LUtil.FormatColorStr(name,nameColor)
			end
		end
		return name
	end
end

function ModelCrossGrading:GetCurCrossGradingIntervalRef(score,rank)
	local curScore = score or self:GetScore()
	local curRank = rank or self:GetRank()
	local rankRefId = self:GetRankRefIdByScore(curScore,curRank)
	return self:GetCrossGradingIntervalByRefId(rankRefId)
end

