function ModelCrossGrading:CheckIsEmptyFormation()
	local teamCount = self:GetTeamCount() - 1
	local isHaveFormationInfo = false
	for i = 0,teamCount do
		isHaveFormationInfo = false
		local formationInfo = gModelFormation:GetFormation(LCombatTypeConst.COMBAT_CROSSGRADING_RANK,i)
		if formationInfo then
			local grids = formationInfo.grids or {}
			local len = #grids
			if len <= 0 then
				isHaveFormationInfo = true
				break
			end
		else
			isHaveFormationInfo = true
			break
		end
	end
	return isHaveFormationInfo
end

