function ModelCrossGrading:StartBattlePlay(combatData)

	local combatType = LCombatTypeConst.COMBAT_CROSSGRADING_RANK

	local wndPara = {
		combatResult = combatData,
		wndName = "UIringFightResult"
	}
	local combatData =
	{
		combatType = combatType,
		reportList = combatData.reportIdList,
		isBattleToBackground = false,
		serverId = combatData.serverId,
		isNew = true,
		battleEndfun = function()
			gModelBattle:OpenCommonResult(wndPara)
		end,
		winnerNumber = combatData.winnerNumber,
	}


	gModelBattle:StartContinueBattle(combatType,combatData)
end

function ModelCrossGrading:OpenRecordDetailsByVideoCenter(info)
	if not info then return end
	local report = info.report
	local crossGradingInfo = info.crossGradingInfo
	local returnCallFunc = info.returnCallFunc
	local viewType = info.viewType
	GF.OpenWnd("UIKuafuGradRecordDetails",{
		report = report,crossGradingInfo = crossGradingInfo,viewType = viewType,returnCallFunc = returnCallFunc
	})
end

-- 挑战奖励列表
function ModelCrossGrading:GetChallengeRewardList()
    local list = {}
    local dayBattleCount = self:GetBattleCount()
    local crossGradingCombatAwardList = self:GetSortCrossGradingCombatAwardRef()
	local len = #crossGradingCombatAwardList
	local isEndGet = false
	local endNum = 0
    for i,v in ipairs(crossGradingCombatAwardList) do
        local refId = v.refId
        local finishCond = v.finishCond
        local isGetReward = self:CheckBattleBoxReceive(refId)
        local status = 0
        if isGetReward then
            status = 2
        elseif dayBattleCount >= finishCond then
            status = 1
        end
		if i == len then
			endNum = finishCond
			if status == 2 then isEndGet = true end
		end
        local sortNum = self._sortStatusNum[status]
        table.insert(list,{
            reward = v.rewardList,
            name = v.name,
            finishCond = v.finishCond,
            sort = v.sort,
            desc = v.description,
            refId = refId,
            status = status,
            sortNum = sortNum,
			nameColor = v.nameColor,
        })
    end
    table.sort(list,function(a,b)
        local sortNumA,sortNumB = a.sortNum,b.sortNum
        if sortNumA == sortNumB then
            return a.sort < b.sort
        else
            return sortNumA > sortNumB
        end
    end)
    return list,isEndGet,endNum
end

-- 段位奖励列表
function ModelCrossGrading:GetGradingRewardList()
    local list = {}
    local curRef = self:GetCurCrossGradingIntervalRef()
    --local curRefId = curRef and curRef.refId
    local curRefId = self:GetRankMax()
    local intervalList = self:GetCrossGradingIntervalSplitList()
    for i,v in pairs(intervalList) do
        local refId = v.refId
        local isGetReward = self:CheckRankBoxReceive(refId)
        local status = 0
        if isGetReward then
            status = 2
        elseif curRefId and curRefId >= refId then
            status = 1
        end
        local sortNum = self._sortStatusNum[status]
        table.insert(list,{
            reward = v.rewardList,
            sort = v.sort,
            name = ccLngText(v.name),
            refId = refId,
            status = status,
            sortNum = sortNum,
			nameColor = v.nameColor,
        })
    end
    table.sort(list,function(a,b)
        local sortNumA,sortNumB = a.sortNum,b.sortNum
        if sortNumA ~= sortNumB then
			return sortNumA > sortNumB
        end
		return a.sort < b.sort
    end)
    return list
end

-- 挑战奖励红点
function ModelCrossGrading:GetChallengeRewardStatus()
    local status = false
    local list = self:GetChallengeRewardList()
    if not list then return status end
    for i,v in ipairs(list) do
        if status then break end
        status = v.status == 1
    end
    return status
end

-- 段位奖励红点
function ModelCrossGrading:GetGradingRewardStatus()
    local status = false
    local list = self:GetGradingRewardList()
    if not list then return status end
    for i,v in ipairs(list) do
        if status then break end
        status = v.status == 1
    end
    return status
end

function ModelCrossGrading:GetOldScore()
	return self.oldScore
end

function ModelCrossGrading:ShowUpRankWnd()
	local oldScore = self.oldScore
	if not oldScore then return end
	local beforeRef = self:GetCurCrossGradingIntervalRef(oldScore,self.oldRank)
	local afterRef = self:GetCurCrossGradingIntervalRef()
	if beforeRef and afterRef then
		local beforeSort,afterSort = beforeRef.sort,afterRef.sort
		if afterSort > beforeSort then
			GF.OpenWndUp("UIKuafuGradUp",{beforeRankRefId = beforeRef.refId,afterRankRefId = afterRef.refId})
			self.oldScore = nil
			self.oldRank = nil
		else
			self.oldScore = self:GetScore()
			self.oldRank = self:GetRank()
		end
	end
end

function ModelCrossGrading:OpenGroupWndPop()
	self._openGroupPop = true
	gModelCrossGrading:OnCrossRankGroupInfoReq()
end

function ModelCrossGrading:TryOpenGroupWndForeignPop()
	if self._crossGroupId and self._crossGroupId <= 0 then
		return
	end

    --self._openGroupForeignPop = true
    gModelCrossGrading:OnCrossRankGroupInfoReq()
end

function ModelCrossGrading:CheckIsUpScore()
	local oldScore = self.oldScore
	if not oldScore then return 0 end
	local score = self:GetScore()
	local returnNum = score > oldScore and 1 or -1
	self:ShowUpRankWnd()
	return returnNum
end

function ModelCrossGrading:PackShareStr(list)
	local str
	local tStr
	for k,v in pairs(list) do
		tStr = k .. "=" .. v
		if str then
			str = str .. "," .. tStr
		else
			str = tStr
		end
	end
	return str
end

function ModelCrossGrading:UnPackShareStr(str)
	local list = {}
	if not string.isempty(str) then
		str = string.split(str,",")
		for i,v in ipairs(str) do
			v = string.split(v,"=")
			local key = v[1]
			local value = v[2]
			if key == "shareRankRefId" or key == "shareTime" then
				value = tonumber(value)
			end
			list[key] = value
		end
	end
	return list
end
