--- initRef
------------------------------------------------------------------
function ModelCrossGrading:InitCrossGradingConfigRef()
	local initCrossGradingConfigRef = {}
	local ref = GameTable.CrossWarConfigRef
	for k,v in pairs(ref) do
		initCrossGradingConfigRef[k] = v
	end
	local matchInterval = ref.matchInterval  or 15
	self._matchInterval = matchInterval
	local seasonTeamNumList = {}
	local seasonTeamNum = string.split(ref["seasonTeamNum"],";")
	for i,v in ipairs(seasonTeamNum) do
		v = string.split(v,"=")
		seasonTeamNumList[tonumber(v[1])] = tonumber(v[2])
	end
	initCrossGradingConfigRef.seasonTeamNumList = seasonTeamNumList

	local purchaseNumConsumeList = {}
	local purchaseNumConsume = string.split(ref["purchaseNumConsume"],";")
	for i,v in ipairs(purchaseNumConsume) do
		v = string.split(v,"=")
		purchaseNumConsumeList[tonumber(v[1])] = tonumber(v[2])
	end
	initCrossGradingConfigRef.purchaseNumConsumeList = purchaseNumConsumeList

	local reportNumList = {}
	local reportNum = string.split(ref["reportNum"],";")
	for i,v in ipairs(reportNum) do
		table.insert(reportNumList,tonumber(v))
	end
	initCrossGradingConfigRef.reportNumList = reportNumList

	self._initCrossGradingConfigRef = initCrossGradingConfigRef
end

function ModelCrossGrading:InitCrossGradingIntervalRef()
	local minScore
	local initCrossGradingIntervalRef = {}
	local sortCrossGradingList = {}
	local ref = GameTable.CrossWarIntervalRef
	for k,v in pairs(ref) do
		local scoreDown = v.scoreDown
		if minScore and minScore > scoreDown then
			minScore = scoreDown
		else
			minScore = scoreDown
		end

		local info = initCrossGradingIntervalRef[k]
		if not info then
			info = {}
			initCrossGradingIntervalRef[k] = info
		end
		table.insert(sortCrossGradingList,v)

		local allRewardList = {}

		local titleRewardList = {}
		local titleReward = string.split(v.titleReward,",")
		for idx,val in ipairs(titleReward) do
			val = string.split(val,"=")
			local itemType,itemId,itemNum = tonumber(val[1]),tonumber(val[2]),tonumber(val[3])
			local data = {
				itemType = itemType,
				itemId = itemId,
				itemNum = itemNum,
			}
			table.insert(titleRewardList,data)

			table.insert(allRewardList,data)
		end
		info.titleRewardList = titleRewardList

		local endRewardList = {}
		local endReward = string.split(v.endReward,",")
		for idx,val in ipairs(endReward) do
			val = string.split(val,"=")
			local itemType,itemId,itemNum = tonumber(val[1]),tonumber(val[2]),tonumber(val[3])
			local data = {
				itemType = itemType,
				itemId = itemId,
				itemNum = itemNum,
			}
			table.insert(endRewardList,data)

			table.insert(allRewardList,data)
		end
		info.endRewardList = endRewardList

		info.allRewardList = allRewardList

		local rewardList = {}
		local reward = string.split(v.reward,",")
		for idx,val in ipairs(reward) do
			val = string.split(val,"=")
			local itemType,itemId,itemNum = tonumber(val[1]),tonumber(val[2]),tonumber(val[3])
			table.insert(rewardList,{
				itemType = itemType,
				itemId = itemId,
				itemNum = itemNum,
			})
		end
		info.rewardList = rewardList
		info.sort = v.sort
		info.refId = v.refId
		info.name = v.name
		info.icon = v.icon
		info.nameColor = v.nameColor
		info.iconEffect = v.iconEffect
	end

	table.sort(sortCrossGradingList,function(a,b)
		return a.sort < b.sort
	end)
	self._sortCrossGradingList = sortCrossGradingList

	local firstCrossGradingRef = sortCrossGradingList[1]
	if firstCrossGradingRef then
		self._firstCrossGradingRefId = firstCrossGradingRef.refId
	end

	local lastCrossGradingRef = sortCrossGradingList[#sortCrossGradingList]
	if lastCrossGradingRef then
		self._lastCrossGradingRef = lastCrossGradingRef
	end

	self._initCrossGradingIntervalRef = initCrossGradingIntervalRef

	self._minScore = minScore
end

function ModelCrossGrading:InitCrossGradingCombatAwardRef()
    local sortCrossGradingCombatAwardRef = {}
    local ref = GameTable.CrossWarAwardRef
    for k,v in pairs(ref) do
		local infoList = {}
        local rewardList = {}
        local reward = string.split(v.reward,",")
        for idx,val in ipairs(reward) do
            val = string.split(val,"=")
            local itemType,itemId,itemNum = tonumber(val[1]),tonumber(val[2]),tonumber(val[3])
            table.insert(rewardList,{
                itemType = itemType,
                itemId = itemId,
                itemNum = itemNum,
            })
        end
		infoList.rewardList = rewardList
		infoList.refId = v.refId
		infoList.sort = v.sort
		infoList.finishCond = v.finishCond
		infoList.name = v.name
		infoList.description = v.description
		table.insert(sortCrossGradingCombatAwardRef,infoList)
    end

	table.sort(sortCrossGradingCombatAwardRef,function(a,b)
		return a.refId < b.refId
	end)

	self._sortCrossGradingCombatAwardRef = sortCrossGradingCombatAwardRef
end

function ModelCrossGrading:CheckIsReachMaxRank(score,rank)
	local curScore = score or self:GetScore()
	local curRank = rank or self:GetRank()
	local reachMaxRank = false
	local lastCrossGradingRef = self._lastCrossGradingRef
	if lastCrossGradingRef then
		local scoreDown = lastCrossGradingRef.scoreDown
		local playerMax = lastCrossGradingRef.playerMax
		reachMaxRank = curScore >= scoreDown and curRank > playerMax
	end
	return reachMaxRank
end

